solution_code:
#include <iostream>
#include <string>

std::string toBinary8(int x) {
    std::string result(8, '0');
    for (int i = 7; i >= 0; --i) {
        result[i] = (x & 1) ? '1' : '0';
        x >>= 1;
    }
    return result;
}

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int x;
        std::cin >> x;
        std::cout << "0b" << toBinary8(x) << '\n';
    }
    return 0;
}

