#include <iomanip>
#include <string>

int main() {
    std::string mode;
    std::cin >> mode;
    int n;
    std::cin >> n;

    if (mode == "INT") {
        int sum = 0;
        auto accumulate = [](int& acc, int val) { acc *= val; }; // Bug: should add
        for (int i = 0; i < n; ++i) {
            int val;
            std::cin >> val;
            accumulate(sum, val);
        }
        std::cout << "Sum: " << sum << '\n';
    } else {
        double sum = 0.0;
        auto accumulate = [](double& acc, double val) { acc += val; };
        for (int i = 0; i < n; ++i) {
            double val;
            std::cin >> val;
            accumulate(sum, val);
        }
        std::cout << "Sum: " << std::fixed << std::setprecision(1) << sum << '\n';
    }
    return 0;
}

